INSERT INTO documents (id, owner_id, title, language, paper_size, font_family, font_size, created_at, updated_at) VALUES
('20000000-0000-0000-0000-000000000001', 'sample-content', 'Getting Started with Lilia', 'en', 'a4', 'serif', 12, NOW(), NOW());
INSERT INTO blocks (id, document_id, type, content, sort_order, created_at, updated_at) VALUES
('30000000-0000-0000-0000-000000000001', '20000000-0000-0000-0000-000000000001', 'heading', '{"level": 1, "text": "Getting Started with Lilia"}', 0, NOW(), NOW()),
('30000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000001', 'paragraph', '{"text": "Welcome to Lilia, a collaborative editor designed for academic and technical writing. This document will walk you through the main features so you can start writing immediately."}', 1, NOW(), NOW()),
('30000000-0000-0000-0000-000000000003', '20000000-0000-0000-0000-000000000001', 'heading', '{"level": 2, "text": "1. Blocks and Structure"}', 2, NOW(), NOW()),
('30000000-0000-0000-0000-000000000004', '20000000-0000-0000-0000-000000000001', 'paragraph', '{"text": "Documents in Lilia are composed of blocks. Each block has a type — paragraph, heading, equation, figure, code, table, and more. You can add new blocks using the + button on the left side, or type / in an empty paragraph to use slash commands."}', 3, NOW(), NOW()),
('30000000-0000-0000-0000-000000000005', '20000000-0000-0000-0000-000000000001', 'paragraph', '{"text": "Try clicking on this paragraph and editing it. Your changes are saved automatically after a few seconds. You can also press Ctrl+S to save immediately."}', 4, NOW(), NOW()),
('30000000-0000-0000-0000-000000000006', '20000000-0000-0000-0000-000000000001', 'heading', '{"level": 2, "text": "2. Equations"}', 5, NOW(), NOW()),
('30000000-0000-0000-0000-000000000007', '20000000-0000-0000-0000-000000000001', 'paragraph', '{"text": "Lilia has first-class support for mathematical notation using LaTeX syntax. Click on the equation below to edit it:"}', 6, NOW(), NOW()),
('30000000-0000-0000-0000-000000000008', '20000000-0000-0000-0000-000000000001', 'equation', '{"latex": "E = mc^2", "numbered": true}', 7, NOW(), NOW()),
('30000000-0000-0000-0000-000000000009', '20000000-0000-0000-0000-000000000001', 'paragraph', '{"text": "You can also write inline math using the formula panel on the right sidebar. The equation editor supports auto-completion and a symbol toolbar for common LaTeX commands."}', 8, NOW(), NOW()),
('30000000-0000-0000-0000-000000000010', '20000000-0000-0000-0000-000000000001', 'heading', '{"level": 2, "text": "3. Export and Preview"}', 9, NOW(), NOW()),
('30000000-0000-0000-0000-000000000011', '20000000-0000-0000-0000-000000000001', 'paragraph', '{"text": "Use the preview panel to see your document rendered as LaTeX, LML, or Typst. You can export your document in multiple formats including LaTeX, PDF, DOCX, HTML, and Markdown from the export dialog."}', 10, NOW(), NOW()),
('30000000-0000-0000-0000-000000000012', '20000000-0000-0000-0000-000000000001', 'heading', '{"level": 2, "text": "4. Collaboration"}', 11, NOW(), NOW()),
('30000000-0000-0000-0000-000000000013', '20000000-0000-0000-0000-000000000001', 'paragraph', '{"text": "Share your documents with collaborators using the share button in the top bar. You can grant read or write access, and changes sync in real-time. Happy writing!"}', 12, NOW(), NOW());
INSERT INTO documents (id, owner_id, title, language, paper_size, font_family, font_size, created_at, updated_at) VALUES
('20000000-0000-0000-0000-000000000002', 'sample-content', 'Sample Research Paper', 'en', 'a4', 'serif', 12, NOW(), NOW());
INSERT INTO blocks (id, document_id, type, content, sort_order, created_at, updated_at) VALUES
('30000000-0000-0000-0000-000000000101', '20000000-0000-0000-0000-000000000002', 'heading', '{"level": 1, "text": "On the Convergence Properties of Stochastic Gradient Descent in Non-Convex Optimization"}', 0, NOW(), NOW()),
('30000000-0000-0000-0000-000000000102', '20000000-0000-0000-0000-000000000002', 'abstract', '{"text": "We study the convergence behavior of stochastic gradient descent (SGD) methods applied to non-convex loss functions commonly encountered in deep learning. We establish new convergence bounds under relaxed smoothness assumptions and demonstrate that adaptive step-size schedules can significantly improve convergence rates. Our theoretical results are validated through extensive experiments on standard benchmark datasets, confirming the practical relevance of our analysis."}', 1, NOW(), NOW()),
('30000000-0000-0000-0000-000000000103', '20000000-0000-0000-0000-000000000002', 'heading', '{"level": 2, "text": "1. Introduction"}', 2, NOW(), NOW()),
('30000000-0000-0000-0000-000000000104', '20000000-0000-0000-0000-000000000002', 'paragraph', '{"text": "Stochastic gradient descent has become the workhorse optimization algorithm in modern machine learning. Despite its simplicity, understanding its convergence properties in non-convex settings remains an active area of research. The loss landscapes of deep neural networks are highly non-convex, featuring saddle points, local minima, and flat regions that pose challenges for gradient-based optimization."}', 3, NOW(), NOW()),
('30000000-0000-0000-0000-000000000105', '20000000-0000-0000-0000-000000000002', 'paragraph', '{"text": "In this paper, we provide a unified framework for analyzing SGD convergence under weaker assumptions than those typically required in the literature. Specifically, we relax the standard L-smoothness condition to a generalized smoothness notion that better captures the geometry of practical loss functions."}', 4, NOW(), NOW()),
('30000000-0000-0000-0000-000000000106', '20000000-0000-0000-0000-000000000002', 'heading', '{"level": 2, "text": "2. Problem Formulation"}', 5, NOW(), NOW()),
('30000000-0000-0000-0000-000000000107', '20000000-0000-0000-0000-000000000002', 'paragraph', '{"text": "Consider the optimization problem of minimizing a stochastic objective function over a parameter space. We assume access to unbiased gradient estimators with bounded variance. The goal is to find a stationary point that satisfies first-order optimality conditions."}', 6, NOW(), NOW()),
('30000000-0000-0000-0000-000000000108', '20000000-0000-0000-0000-000000000002', 'equation', '{"latex": "\\min_{\\theta \\in \\mathbb{R}^d} f(\\theta) = \\mathbb{E}_{\\xi \\sim \\mathcal{D}} [F(\\theta; \\xi)]", "numbered": true}', 7, NOW(), NOW()),
('30000000-0000-0000-0000-000000000109', '20000000-0000-0000-0000-000000000002', 'paragraph', '{"text": "where F denotes the per-sample loss function and the expectation is taken over the data distribution. The SGD update rule with step size η at iteration t is given by the standard gradient step with a noisy gradient estimate."}', 8, NOW(), NOW()),
('30000000-0000-0000-0000-000000000110', '20000000-0000-0000-0000-000000000002', 'equation', '{"latex": "\\theta_{t+1} = \\theta_t - \\eta_t \\nabla F(\\theta_t; \\xi_t)", "numbered": true}', 9, NOW(), NOW()),
('30000000-0000-0000-0000-000000000111', '20000000-0000-0000-0000-000000000002', 'heading', '{"level": 2, "text": "3. Main Results"}', 10, NOW(), NOW()),
('30000000-0000-0000-0000-000000000112', '20000000-0000-0000-0000-000000000002', 'theorem', '{"type": "theorem", "title": "Convergence Rate", "text": "Under Assumptions 1-3, for step size η_t = c / √T, the iterates of SGD satisfy the convergence bound with rate O(1/√T) to a first-order stationary point."}', 11, NOW(), NOW()),
('30000000-0000-0000-0000-000000000113', '20000000-0000-0000-0000-000000000002', 'paragraph', '{"text": "The proof proceeds by constructing a Lyapunov function and bounding the expected decrease in the objective at each step. The key technical contribution is handling the interaction between gradient noise and the non-convex landscape geometry without requiring global Lipschitz continuity of the gradient."}', 12, NOW(), NOW()),
('30000000-0000-0000-0000-000000000114', '20000000-0000-0000-0000-000000000002', 'heading', '{"level": 2, "text": "4. Experimental Validation"}', 13, NOW(), NOW()),
('30000000-0000-0000-0000-000000000115', '20000000-0000-0000-0000-000000000002', 'paragraph', '{"text": "We validate our theoretical findings on CIFAR-10 and ImageNet classification tasks using ResNet and Vision Transformer architectures. The experiments confirm that the predicted convergence rates closely match empirical observations across different model scales and data regimes."}', 14, NOW(), NOW()),
('30000000-0000-0000-0000-000000000116', '20000000-0000-0000-0000-000000000002', 'heading', '{"level": 2, "text": "5. Conclusion"}', 15, NOW(), NOW()),
('30000000-0000-0000-0000-000000000117', '20000000-0000-0000-0000-000000000002', 'paragraph', '{"text": "We have presented a refined analysis of SGD convergence in non-convex optimization, establishing tighter bounds under weaker assumptions. Our results bridge the gap between theoretical convergence guarantees and practical performance, providing actionable guidance for step-size selection and training schedules in deep learning."}', 16, NOW(), NOW()),
('30000000-0000-0000-0000-000000000118', '20000000-0000-0000-0000-000000000002', 'heading', '{"level": 2, "text": "References"}', 17, NOW(), NOW()),
('30000000-0000-0000-0000-000000000119', '20000000-0000-0000-0000-000000000002', 'bibliography', '{}', 18, NOW(), NOW());
