UPDATE templates SET content = '{"language": "en", "paperSize": "a4", "fontFamily": "serif", "fontSize": 12, "blocks": [{"type": "heading", "content": {"level": 1, "text": "Paper Title"}, "sortOrder": 0}, {"type": "abstract", "content": {"text": "This paper investigates the fundamental properties of the proposed framework and establishes key theoretical results. We demonstrate the effectiveness of our approach through rigorous analysis and comprehensive experiments, showing significant improvements over existing methods in both accuracy and computational efficiency."}, "sortOrder": 1}, {"type": "heading", "content": {"level": 2, "text": "1. Introduction"}, "sortOrder": 2}, {"type": "paragraph", "content": {"text": "The study of complex systems has been a central theme in modern science and engineering. Recent advances in computational methods have opened new avenues for understanding phenomena that were previously intractable. In this work, we present a novel approach that combines theoretical rigor with practical applicability."}, "sortOrder": 3}, {"type": "heading", "content": {"level": 2, "text": "2. Methods"}, "sortOrder": 4}, {"type": "paragraph", "content": {"text": "Our methodology builds on established techniques from functional analysis and extends them to handle the non-standard boundary conditions encountered in practice. We formulate the problem as a variational optimization and derive efficient algorithms for its solution."}, "sortOrder": 5}, {"type": "heading", "content": {"level": 2, "text": "3. Results"}, "sortOrder": 6}, {"type": "paragraph", "content": {"text": "The experimental results demonstrate that our proposed method achieves state-of-the-art performance across all benchmark datasets. Statistical significance tests confirm the reliability of the observed improvements, with p-values below 0.01 in all comparisons."}, "sortOrder": 7}, {"type": "heading", "content": {"level": 2, "text": "4. Discussion"}, "sortOrder": 8}, {"type": "paragraph", "content": {"text": "The results support our initial hypothesis and suggest several promising directions for future investigation. The robustness of the method across different experimental conditions indicates broad applicability beyond the specific domains considered here."}, "sortOrder": 9}, {"type": "heading", "content": {"level": 2, "text": "5. Conclusion"}, "sortOrder": 10}, {"type": "paragraph", "content": {"text": "We have presented a comprehensive study of the proposed framework, demonstrating both its theoretical soundness and practical utility. Future work will focus on extending the approach to handle larger-scale problems and more complex domain geometries."}, "sortOrder": 11}, {"type": "heading", "content": {"level": 2, "text": "References"}, "sortOrder": 12}, {"type": "bibliography", "content": {}, "sortOrder": 13}], "bibliography": []}'
WHERE id = '10000000-0000-0000-0000-000000000002';

UPDATE templates SET content = '{"language": "en", "paperSize": "a4", "fontFamily": "serif", "fontSize": 12, "blocks": [{"type": "heading", "content": {"level": 1, "text": "Physics Homework — Set 1"}, "sortOrder": 0}, {"type": "paragraph", "content": {"text": "Name: ________________  Date: ________________"}, "sortOrder": 1}, {"type": "pageBreak", "content": {}, "sortOrder": 2}, {"type": "heading", "content": {"level": 2, "text": "Problem 1"}, "sortOrder": 3}, {"type": "paragraph", "content": {"text": "A particle of mass m is launched vertically upward with initial velocity v₀ from the surface of the Earth. Ignoring air resistance, determine the maximum height reached and the total time of flight."}, "sortOrder": 4}, {"type": "heading", "content": {"level": 3, "text": "Solution"}, "sortOrder": 5}, {"type": "equation", "content": {"latex": "h_{\\max} = \\frac{v_0^2}{2g}", "numbered": true}, "sortOrder": 6}, {"type": "heading", "content": {"level": 2, "text": "Problem 2"}, "sortOrder": 7}, {"type": "paragraph", "content": {"text": "Two blocks of masses m₁ = 3 kg and m₂ = 5 kg are connected by a light string passing over a frictionless pulley. Calculate the acceleration of the system and the tension in the string."}, "sortOrder": 8}, {"type": "heading", "content": {"level": 3, "text": "Solution"}, "sortOrder": 9}, {"type": "equation", "content": {"latex": "a = \\frac{(m_2 - m_1)g}{m_1 + m_2} = \\frac{(5 - 3) \\times 9.8}{5 + 3} = 2.45 \\text{ m/s}^2", "numbered": true}, "sortOrder": 10}], "bibliography": []}'
WHERE id = '10000000-0000-0000-0000-000000000003';

UPDATE templates SET content = '{"language": "en", "paperSize": "a4", "fontFamily": "serif", "fontSize": 12, "blocks": [{"type": "heading", "content": {"level": 1, "text": "Chapter 1: Theoretical Foundations"}, "sortOrder": 0}, {"type": "paragraph", "content": {"text": "This chapter establishes the theoretical framework upon which the remainder of the thesis is built. We begin with a review of the relevant literature before presenting the core definitions and assumptions."}, "sortOrder": 1}, {"type": "heading", "content": {"level": 2, "text": "1.1 Introduction"}, "sortOrder": 2}, {"type": "paragraph", "content": {"text": "The origins of the field can be traced back to the seminal work of the early twentieth century, when the fundamental equations governing the behavior of the system were first derived. Since then, a rich body of theory has emerged, providing deep insights into the structure and dynamics of these complex systems."}, "sortOrder": 3}, {"type": "heading", "content": {"level": 2, "text": "1.2 Background"}, "sortOrder": 4}, {"type": "paragraph", "content": {"text": "We review the key concepts and prior results that form the basis of our analysis. Particular attention is given to the conditions under which the classical theory applies and the known limitations that motivate the extensions proposed in this thesis."}, "sortOrder": 5}, {"type": "heading", "content": {"level": 2, "text": "1.3 Core Definitions"}, "sortOrder": 6}, {"type": "paragraph", "content": {"text": "Let us define the principal objects of study and establish the notation that will be used throughout. We adopt the convention that bold symbols denote vectors and capital letters denote matrices unless otherwise stated."}, "sortOrder": 7}, {"type": "heading", "content": {"level": 2, "text": "1.4 Summary"}, "sortOrder": 8}, {"type": "paragraph", "content": {"text": "In this chapter, we have laid the groundwork for the analysis to follow. The definitions and assumptions introduced here will be referenced extensively in the subsequent chapters, where we develop our main contributions."}, "sortOrder": 9}], "bibliography": []}'
WHERE id = '10000000-0000-0000-0000-000000000004';

UPDATE templates SET content = '{"language": "en", "paperSize": "a4", "fontFamily": "serif", "fontSize": 12, "blocks": [{"type": "heading", "content": {"level": 1, "text": "The Spectral Gap Theorem"}, "sortOrder": 0}, {"type": "theorem", "content": {"type": "theorem", "title": "Spectral Gap", "text": "Let A be a self-adjoint operator on a separable Hilbert space H with spectrum σ(A). If the infimum of the essential spectrum satisfies inf σ_ess(A) > inf σ(A), then the lowest eigenvalue λ₁ is isolated and has finite multiplicity."}, "sortOrder": 1}, {"type": "theorem", "content": {"type": "proof", "title": "", "text": "We proceed by contradiction. Suppose the infimum of the spectrum is not an isolated eigenvalue. Then there exists a sequence of approximate eigenvectors {φₙ} with ‖φₙ‖ = 1 such that ‖(A - λ₁)φₙ‖ → 0 as n → ∞. By the spectral theorem, this implies that λ₁ belongs to the essential spectrum, contradicting our assumption that inf σ_ess(A) > λ₁. The finite multiplicity follows from the discreteness of the spectrum below the essential spectrum threshold. □"}, "sortOrder": 2}], "bibliography": []}'
WHERE id = '10000000-0000-0000-0000-000000000005';

UPDATE templates SET content = '{"language": "en", "paperSize": "a4", "fontFamily": "serif", "fontSize": 12, "blocks": [{"type": "heading", "content": {"level": 1, "text": "Lab Report: Determination of the Speed of Sound in Air"}, "sortOrder": 0}, {"type": "paragraph", "content": {"text": "Author: ________________  Date: ________________"}, "sortOrder": 1}, {"type": "heading", "content": {"level": 2, "text": "Objective"}, "sortOrder": 2}, {"type": "paragraph", "content": {"text": "To determine the speed of sound in air at room temperature using the resonance tube method, and to compare the experimental result with the theoretical prediction based on the ideal gas model."}, "sortOrder": 3}, {"type": "heading", "content": {"level": 2, "text": "Materials and Methods"}, "sortOrder": 4}, {"type": "paragraph", "content": {"text": "A glass resonance tube of length 1.2 m was partially filled with water. A tuning fork of known frequency (f = 440 Hz) was struck and held above the open end while the water level was gradually lowered. The positions of successive resonance points were recorded."}, "sortOrder": 5}, {"type": "heading", "content": {"level": 2, "text": "Results"}, "sortOrder": 6}, {"type": "paragraph", "content": {"text": "The first resonance was observed at a tube length of 19.2 cm, and the second at 57.8 cm. The difference between successive resonance positions gives half the wavelength: λ/2 = 38.6 cm, yielding λ = 77.2 cm."}, "sortOrder": 7}, {"type": "equation", "content": {"latex": "v = f \\lambda = 440 \\times 0.772 = 339.7 \\text{ m/s}", "numbered": true}, "sortOrder": 8}, {"type": "heading", "content": {"level": 2, "text": "Analysis"}, "sortOrder": 9}, {"type": "paragraph", "content": {"text": "The measured speed of 339.7 m/s is within 1% of the accepted value of 343 m/s at 20°C. The small discrepancy can be attributed to the end correction effect and slight temperature variations during the experiment."}, "sortOrder": 10}, {"type": "heading", "content": {"level": 2, "text": "Conclusion"}, "sortOrder": 11}, {"type": "paragraph", "content": {"text": "The resonance tube method provides an accurate determination of the speed of sound in air. The experimental value agrees well with theoretical predictions, validating both the measurement technique and the underlying wave mechanics model."}, "sortOrder": 12}], "bibliography": []}'
WHERE id = '10000000-0000-0000-0000-000000000006';
